def get_all_stocks():
    """Get complete stock database"""

    all_stocks = (
        NIFTY50 +
        NIFTYNEXT50 +
        NIFTY100 +
        NIFTYSMALLCAP100 +
        NIFTY_MIDCAP150_STOCKS +
        NIFTY200 +
        NIFTY500 +
        NIFTYTOTALMARKET +
        NIFTY_CHEMICALS +
        NIFTY_METAL +
        NIFTY_OILANDGAS +
        NIFTY_CONSUMER_DURABLES_STOCKS +
        NIFTY_REALTY +
        NIFTY_AUTO +
        NIFTY_BANK +
        NIFTY_FINANCIAL_SERVICES_STOCKS +
        NIFTY_FINANCIAL_SERVICES25_50LIST_STOCKS +
        NIFTY_PRIVATEBANK +
        NIFTY_PSUBANK +
        NIFTY_FMCG +
        NIFTY_IT +
        NIFTY_MEDIA
    )

    # De-duplicate by symbol to keep the database lean
    seen = set()
    unique_stocks = []
    for s in all_stocks:
        if s['symbol'] not in seen:
            unique_stocks.append(s)
            seen.add(s['symbol'])

    return unique_stocks


