ALL_STOCKS_DB = get_all_stocks()


# -----------------------------
# Get stocks by Index
# -----------------------------
def get_stocks_by_index(index_name: str):
    """
    Return stocks belonging to a given index
    """

    return [
        stock for stock in ALL_STOCKS_DB
        if stock.get("index") == index_name
    ]


# -----------------------------
# Get stocks by Sector
# -----------------------------
def get_stocks_by_sector(sector_name: str):
    """
    Return stocks belonging to a sector
    """

    return [
        stock for stock in ALL_STOCKS_DB
        if stock.get("sector") == sector_name
    ]


# -----------------------------
# Get stock by symbol
# -----------------------------
def get_stock_by_symbol(symbol: str):
    """
    Fetch single stock details
    """

    for stock in ALL_STOCKS_DB:
        if stock.get("symbol") == symbol:
            return stock

    return None


# -----------------------------
# Get all symbols
# -----------------------------
def get_all_symbols():
    """
    Return all stock symbols
    """

    return [
        stock.get("symbol")
        for stock in ALL_STOCKS_DB
        if stock.get("symbol")
    ]


# -----------------------------
# Get all sectors
# -----------------------------
def get_all_sectors():
    """
    Return unique sectors
    """

    return list({
        stock.get("sector")
        for stock in ALL_STOCKS_DB
        if stock.get("sector")
    })


# -----------------------------
# Get all indexes
# -----------------------------
def get_all_indexes():
    """
    Return unique indexes
    """

    return list({
        stock.get("index")
        for stock in ALL_STOCKS_DB
        if stock.get("index")
    })